import React from 'react'

const Hooks = () => {
    const getData = () => {
        return {
            count1: 1,
            count2: 2,
        }
    }
    const [state, setState] = React.useState(getData());
    const handleIncrement = () => {
        setCount(prevState => ({...prevState, count1: prevState.count1 + 1}));
    }
    const handleDecrement = () => {
        setCount(prevState => ({...prevState, count2: prevState.count2 - 1}));
    }
    
  return (
      <div style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          height: '100vh',
        }
      }>
          <h1>Hooks</h1>
          <button style={{
              width: '50px',
              height: '50px',
              backgroundColor: 'grey',
              color: 'white',
              fontSize: '20px',
              border: '5px solid black',
          }}
              onClick={handleIncrement}>+</button>
          <h2>{count}</h2>
          <button 
              style={{
                  width: '50px',
                  height: '50px',
                  backgroundColor: 'red',
                  color: 'white',
                  fontSize: '20px',
              }}
              onClick={handleDecrement}>-</button>
          
    </div>
  )
}

export default Hooks
